import graphene
import psycopg2
from psycopg2.extras import RealDictCursor
from graphql import GraphQLError
import re

class SearchInput(graphene.InputObjectType):
    search_term = graphene.String(required=True)
    fields = graphene.List(graphene.String)
    limit = graphene.Int(default_value=100)
    offset = graphene.Int(default_value=0)

class SearchResult(graphene.ObjectType):
    id = graphene.Int()
    name = graphene.String()
    description = graphene.String()
    created_at = graphene.DateTime()

class Query(graphene.ObjectType):
    search = graphene.List(
        SearchResult,
        input=graphene.Argument(SearchInput),
        description="Search across multiple fields with dynamic SQL"
    )

    def resolve_search(self, info, input):
        try:
            # Validate input
            if not input.search_term or len(input.search_term.strip()) < 1:
                raise GraphQLError("Search term must be at least 1 character long")
            
            if input.limit < 0 or input.limit > 1000:
                raise GraphQLError("Limit must be between 0 and 1000")
            
            # Sanitize search term for SQL
            search_term = re.sub(r'[^\w\s\-\.]', '', input.search_term)
            if not search_term:
                return []
            
            # Default fields if none provided
            if not input.fields:
                fields = ['name', 'description']
            else:
                # Validate field names against allowed list
                allowed_fields = ['name', 'description', 'id']
                fields = [f for f in input.fields if f in allowed_fields]
                if not fields:
                    raise GraphQLError("No valid fields provided for search")
            
            # Build dynamic SQL query
            where_conditions = []
            params = []
            
            for i, field in enumerate(fields):
                where_conditions.append(f"{field} ILIKE %s")
                params.append(f"%{search_term}%")
            
            sql = f"""
                SELECT id, name, description, created_at 
                FROM items 
                WHERE {' OR '.join(where_conditions)}
                ORDER BY created_at DESC
                LIMIT %s OFFSET %s
            """
            
            params.extend([input.limit, input.offset])
            
            # Execute query
            conn = psycopg2.connect(
                host="localhost",
                database="your_db",
                user="your_user",
                password="your_password"
            )
            
            cursor = conn.cursor(cursor_factory=RealDictCursor)
            cursor.execute(sql, params)
            results = cursor.fetchall()
            cursor.close()
            conn.close()
            
            return [SearchResult(**row) for row in results]
            
        except Exception as e:
            raise GraphQLError(f"Search failed: {str(e)}")

